11	constexpr int GRID_SIZE = 30;
12	constexpr int NUM_TURNS = 300;
13	constexpr int INF = std::numeric_limits<int>::max();
14	
15	struct Point {
16	    int r, c;
17	    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
18	    bool operator!=(const Point& o) const { return !(*this == o); }
19	};
20	
21	const int DR[4] = {-1, 1, 0, 0};
22	const int DC[4] = {0, 0, -1, 1};
23	const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
24	const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};
25	
26	bool grid[GRID_SIZE + 2][GRID_SIZE + 2];
27	
28	int N, M;
29	std::vector<Point> pets;
30	std::vector<int> pet_types;
31	std::vector<Point> humans;
32	
33	bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
34	bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }
35	
36	int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
37	Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];
38	
39	void compute_bfs_from(Point src) {
40	    memset(bfs_dist, -1, sizeof(bfs_dist));
41	    std::queue<Point> q;
42	    bfs_dist[src.r][src.c] = 0;
43	    q.push(src);
44	    while (!q.empty()) {
45	        Point cur = q.front(); q.pop();
46	        for (int d = 0; d < 4; d++) {
47	            int nr = cur.r + DR[d], nc = cur.c + DC[d];
48	            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
49	                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
50	                bfs_parent[nr][nc] = cur;
51	                q.push({nr, nc});
52	            }
53	        }
54	    }
55	}
56	
57	char move_toward(Point from, Point to) {
58	    if (from == to) return '.';
59	    compute_bfs_from(from);
60	    if (bfs_dist[to.r][to.c] == -1) return '.';
61	
62	    Point cur = to;
63	    while (!(bfs_parent[cur.r][cur.c] == from)) {
64	        cur = bfs_parent[cur.r][cur.c];
65	    }
66	    for (int d = 0; d < 4; d++) {
67	        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
68	            return MOVE_CH[d];
69	        }
70	    }
71	    return '.';
72	}
73	
74	bool can_build_wall(int r, int c) {
75	    if (!valid(r, c)) return false;
76	    if (grid[r][c]) return false;
77	    for (auto& p : pets) {
78	        if (p.r == r && p.c == c) return false;
79	        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
80	    }
81	    for (int i = 0; i < M; i++) {
82	        if (humans[i].r == r && humans[i].c == c) return false;
83	    }
84	    return true;
85	}
