217	// Also compute dual horizontal wall score for comparison
218	double compute_dual_wall_score(int tr, int br) {
219	    int pets_above = 0, pets_below = 0;
220	    for (auto& p : pets) {
221	        if (p.r < tr) pets_above++;
222	        else if (p.r > br) pets_below++;
223	    }
224	    int area_above = (tr - 1) * GRID_SIZE;
225	    int area_below = (GRID_SIZE - br) * GRID_SIZE;
226	    double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
227	    double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
228	    return (sa + sb) / 2.0;
229	}
230	
231	// Mode: 0 = dual L-shape, 1 = dual horizontal walls (fallback)
232	int strategy_mode;
233	int dual_wall_top, dual_wall_bot;
234	
235	void choose_strategy() {
236	    // Find best corner plans for each corner
237	    CornerPlan corners[4];
238	    for (int i = 0; i < 4; i++) {
239	        find_best_corner(i, corners[i]);
240	    }
241	
242	    // Best pair of any two corners (check all 6 pairs, not just opposite)
243	    double best_pair_score = -1;
244	    int best_pair[2] = {0, 3};
245	
246	    for (int a = 0; a < 4; a++) {
247	        for (int b = a + 1; b < 4; b++) {
248	            // Check that the two plans don't overlap in their sealed regions
249	            bool overlap = !(plans[0].r_max < plans[1].r_min || plans[1].r_max < plans[0].r_min ||
250	                           plans[0].c_max < plans[1].c_min || plans[1].c_max < plans[0].c_min);
251	            // Use corners a and b
252	            int r_min_a = corners[a].r_min, r_max_a = corners[a].r_max;
253	            int c_min_a = corners[a].c_min, c_max_a = corners[a].c_max;
254	            int r_min_b = corners[b].r_min, r_max_b = corners[b].r_max;
255	            int c_min_b = corners[b].c_min, c_max_b = corners[b].c_max;
256	
257	            bool regions_overlap = !(r_max_a < r_min_b || r_max_b < r_min_a ||
258	                                    c_max_a < c_min_b || c_max_b < c_min_a);
259	            if (regions_overlap) continue;
260	
261	            double combined = corners[a].score + corners[b].score;
262	            if (combined > best_pair_score) {
263	                best_pair_score = combined;
264	                best_pair[0] = a;
265	                best_pair[1] = b;
266	            }
267	        }
268	    }
269	
270	    // Also try single best corner (all humans in one corner)
271	    double best_single_score = -1;
272	    int best_single = 0;
273	    for (int i = 0; i < 4; i++) {
274	        if (corners[i].score > best_single_score) {
275	            best_single_score = corners[i].score;
276	            best_single = i;
277	        }
278	    }
279	
280	    // Compare with dual horizontal walls
281	    double best_dual_h = -1;
282	    int best_tr = 8, best_br = 23;
283	    for (int tr = 3; tr <= 15; tr++) {
284	        for (int br = tr + 4; br <= 28; br++) {
285	            double s = compute_dual_wall_score(tr, br);
286	            if (s > best_dual_h) {
287	                best_dual_h = s;
288	                best_tr = tr;
289	                best_br = br;
290	            }
291	        }
292	    }
293	
294	    // Choose strategy
295	    // L-shape advantages: faster build, better pet isolation when corners are clean
296	    // Give L-shape a 20% bonus for faster construction
297	    double l_pair_effective = best_pair_score * 1.2;
298	    double l_single_effective = best_single_score * 1.3; // single is even faster
299	
300	    if (l_pair_effective > best_dual_h && l_pair_effective > l_single_effective) {
301	        strategy_mode = 0;
302	        num_plans = 2;
303	        plans[0] = corners[best_pair[0]];
304	        plans[1] = corners[best_pair[1]];
305	    } else if (l_single_effective > best_dual_h) {
306	        strategy_mode = 0;
307	        num_plans = 1;
308	        plans[0] = corners[best_single];
309	    } else {
310	        strategy_mode = 1;
311	        dual_wall_top = best_tr;
312	        dual_wall_bot = best_br;
313	    }
314	}
315	
316	// Human assignment for L-shape strategy
317	int human_plan_assignment[10]; // which plan (0 or 1)
318	
319	// Wall cells to build for each plan
320	std::vector<Point> plan_walls[2];
321	
322	void assign_humans_lshape() {
323	    if (num_plans == 1) {
324	        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
325	        return;
326	    }
327	
328	    // Split humans between two plans based on proximity
329	    int count0 = M / 2;
330	
331	    std::vector<std::pair<double, int>> preference(M);
332	    for (int i = 0; i < M; i++) {
333	        // Distance to center of plan 0 region
334	        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
335	        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
336	        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
337	
338	        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
339	        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
340	        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
341	
342	        preference[i] = {d0 - d1, i};
343	    }
344	    std::sort(preference.begin(), preference.end());
345	
346	    int assigned0 = 0;
347	    for (auto& [pref, idx] : preference) {
348	        if (assigned0 < count0) {
349	            human_plan_assignment[idx] = 0;
350	            assigned0++;
351	        } else {
352	            human_plan_assignment[idx] = 1;
353	        }
354	    }
355	}
356	
357	// For dual horizontal wall fallback
358	int human_wall_assignment_h[10]; // 0=top, 1=bot
359	
360	void assign_humans_dual_h() {
361	    int top_count = M / 2;
362	    std::vector<std::pair<int, int>> preference(M);
363	    for (int i = 0; i < M; i++) {
364	        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
365	    }
366	    std::sort(preference.begin(), preference.end());
367	    int assigned_top = 0;
368	    for (auto& [pref, idx] : preference) {
369	        if (assigned_top < top_count) {
370	            human_wall_assignment_h[idx] = 0;
371	            assigned_top++;
372	        } else {
373	            human_wall_assignment_h[idx] = 1;
374	        }
375	    }
376	}
