378	int main() {
379	    std::ios_base::sync_with_stdio(false);
380	    std::cin.tie(NULL);
381	
382	    std::cin >> N;
383	    pets.resize(N);
384	    pet_types.resize(N);
385	    for (int i = 0; i < N; i++) {
386	        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
387	    }
388	
389	    std::cin >> M;
390	    humans.resize(M);
391	    for (int i = 0; i < M; i++) {
392	        std::cin >> humans[i].r >> humans[i].c;
393	    }
394	
395	    memset(grid, false, sizeof(grid));
396	    choose_strategy();
397	
398	    if (strategy_mode == 0) {
399	        // L-shape mode
400	        for (int p = 0; p < num_plans; p++) {
401	            plan_walls[p] = get_wall_cells(plans[p]);
402	        }
403	        assign_humans_lshape();
404	    } else {
405	        // Dual horizontal wall mode
406	        assign_humans_dual_h();
407	    }
408	
409	    for (int turn = 0; turn < NUM_TURNS; turn++) {
410	        std::string actions(M, '.');
411	        std::vector<Point> walls_being_built;
412	
413	        if (strategy_mode == 0) {
414	            // L-shape strategy
415	            for (int i = 0; i < M; i++) {
416	                int my_plan = human_plan_assignment[i];
417	                auto& my_walls = plan_walls[my_plan];
418	                auto& plan = plans[my_plan];
419	
420	                // Find best unbuilt wall cell: balance proximity to human and priority from corner outward
421	                int best_idx = -1;
422	                int best_priority = INF;
423	
424	                // The intersection point of the L-shape
425	                int corner_r = plan.wall_row;
426	                int corner_c = plan.wall_col;
427	
428	                for (int w = 0; w < (int)my_walls.size(); w++) {
429	                    Point wc = my_walls[w];
430	                    if (grid[wc.r][wc.c]) continue;
431	
432	                    // Check not already claimed this turn
433	                    bool claimed = false;
434	                    for (auto& wb : walls_being_built) {
435	                        if (wb == wc) { claimed = true; break; }
436	                    }
437	                    if (claimed) continue;
438	
439	                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
440	                    // Distance from corner intersection (build from corner outward)
441	                    int corner_dist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);
442	                    // Combined priority: mostly distance but with a small bias toward corner
443	                    int priority = dist * 2 + corner_dist;
444	                    if (priority < best_priority) {
445	                        best_priority = priority;
446	                        best_idx = w;
447	                    }
448	                }
449	
450	                if (best_idx == -1) {
451	                    // All walls built - move to center of safe zone
452	                    int tr = (plan.r_min + plan.r_max) / 2;
453	                    int tc = (plan.c_min + plan.c_max) / 2;
454	                    Point target = {tr, tc};
455	                    if (!passable(target.r, target.c)) {
456	                        // Find any passable cell in safe zone
457	                        bool found = false;
458	                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
459	                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
460	                                if (passable(r, c)) {
461	                                    target = {r, c};
462	                                    found = true;
463	                                }
464	                            }
465	                        }
466	                    }
467	                    if (humans[i] != target) {
468	                        actions[i] = move_toward(humans[i], target);
469	                    }
470	                } else {
471	                    Point wall_target = my_walls[best_idx];
472	
473	                    // Find a position adjacent to wall_target from the SAFE side
474	                    Point stand_pos = {-1, -1};
475	                    int best_stand_dist = INF;
476	
477	                    for (int d = 0; d < 4; d++) {
478	                        int sr = wall_target.r + DR[d];
479	                        int sc = wall_target.c + DC[d];
480	                        if (!passable(sr, sc)) continue;
481	
482	                        // Prefer standing inside the safe zone
483	                        bool in_safe = is_safe_side(plan, sr, sc);
484	
485	                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
486	                        // Give big bonus to safe-side positions
487	                        int effective_dist = in_safe ? dist : dist + 100;
488	
489	                        if (effective_dist < best_stand_dist) {
490	                            best_stand_dist = effective_dist;
491	                            stand_pos = {sr, sc};
492	                        }
493	                    }
494	
495	                    if (stand_pos.r == -1) {
496	                        // Can't find standing position, try any adjacent
497	                        for (int d = 0; d < 4; d++) {
498	                            int sr = wall_target.r + DR[d];
499	                            int sc = wall_target.c + DC[d];
500	                            if (passable(sr, sc)) {
501	                                stand_pos = {sr, sc};
502	                                break;
503	                            }
504	                        }
505	                    }
506	
507	                    if (stand_pos.r == -1) {
508	                        actions[i] = '.';
509	                    } else if (humans[i] == stand_pos) {
510	                        // Build the wall
511	                        if (can_build_wall(wall_target.r, wall_target.c)) {
512	                            for (int d = 0; d < 4; d++) {
513	                                if (humans[i].r + DR[d] == wall_target.r &&
514	                                    humans[i].c + DC[d] == wall_target.c) {
515	                                    actions[i] = BUILD_CH[d];
516	                                    walls_being_built.push_back(wall_target);
517	                                    break;
518	                                }
519	                            }
520	                        } else {
