# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Diagonal wall strategy: seal triangular corner regions using anti-diagonal walls.
// A diagonal of D cells seals D*(D-1)/2 area - roughly 2x area per wall cell vs L-shapes.

struct DiagPlan {
    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
    int D;      // diagonal parameter (wall length = D cells)
    int area;
    double score;
};

// Get wall cells for a diagonal plan
std::vector<Point> get_diag_wall_cells(int corner, int D) {
    std::vector<Point> cells;
    for (int i = 1; i <= D; i++) {
        int r, c;
        if (corner == 0) { // TL: wall on r+c = D+1
            r = i; c = D + 1 - i;
        } else if (corner == 1) { // TR: wall cells (i, 30-D+i)
            r = i; c = 30 - D + i;
        } else if (corner == 2) { // BL: wall cells (30-D+i, i)
            r = 30 - D + i; c = i;
        } else { // BR: wall cells (30-D+i, 31-i)
            r = 30 - D + i; c = 31 - i;
        }
        if (valid(r, c)) cells.push_back({r, c});
    }
    return cells;
}

bool is_in_safe_zone(int corner, int D, int r, int c) {
    if (corner == 0) return (r + c <= D);
    if (corner == 1) return (r + (31 - c) <= D); // r + 31 - c <= D -> c >= 31 - D + r
    if (corner == 2) return ((31 - r) + c <= D); // 31 - r + c <= D -> r >= 31 - D + c
    return ((31 - r) + (31 - c) <= D); // 62 - r - c <= D -> r + c >= 62 - D
}

// Distance metric from corner
int corner_dist(int corner, int r, int c) {
    if (corner == 0) return r + c;
    if (corner == 1) return r + (31 - c);
    if (corner == 2) return (31 - r) + c;
    return (31 - r) + (31 - c);
}

// Get safe-side adjacent cells for a wall cell (cells on the safe side)
std::vector<Point> get_safe_adjacent(int corner, int D, Point wall_cell) {
    std::vector<Point> result;
    for (int d = 0; d < 4; d++) {
        int nr = wall_cell.r + DR[d], nc = wall_cell.c + DC[d];
        if (valid(nr, nc) && is_in_safe_zone(corner, D, nr, nc)) {
            result.push_back({nr, nc});
        }
    }
    return result;
}

DiagPlan best_plans[4]; // best plan for each corner
int num_active_plans;
DiagPlan active_plans[4];
int human_plan_assignment[10];
std::vector<Point> plan_walls[4];

void evaluate_corner(int corner_id) {
    best_plans[corner_id].score = -1;
    best_plans[corner_id].corner = corner_id;

    for (int D = 3; D <= 25; D++) {
        int area = D * (D - 1) / 2;
        if (area < 20) continue;

        // Count pets inside safe zone
        int pets_inside = 0;
        int pets_on_wall = 0; // pets adjacent to wall (leakage risk)

        for (auto& p : pets) {
            if (is_in_safe_zone(corner_id, D, p.r, p.c)) {
                pets_inside++;
            }
            // Check if pet is on the wall line or adjacent to it
            int pd = corner_dist(corner_id, p.r, p.c);
            if (pd == D + 1) pets_on_wall++; // pet ON the wall line
            if (pd == D + 2) pets_on_wall++; // pet just outside wall (adjacent to wall cells)
        }

        double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);

        // Construction cost factor (fewer cells = better)
        double cost_factor = 1.0 / (1.0 + D * 0.01);

        // Reward 0 pets inside
        double pet_bonus = (pets_inside == 0) ? 2.0 : std::pow(0.7, pets_inside);

        // Penalize pets near wall (leakage risk during construction)
        double near_penalty = 1.0 / (1.0 + pets_on_wall * 0.15);

        // Human distance to the safe zone
        double avg_human_dist = 0;
        for (int hi = 0; hi < M; hi++) {
            int hd = corner_dist(corner_id, humans[hi].r, humans[hi].c);
            if (hd <= D) {
                avg_human_dist += 0; // already inside
            } else {
                avg_human_dist += hd - D;
            }
        }
        avg_human_dist /= M;
        double dist_factor = 1.0 / (1.0 + avg_human_dist * 0.02);

        double score = base_score * cost_factor * pet_bonus * dist_factor * near_penalty;

        if (score > best_plans[corner_id].score) {
            best_plans[corner_id].corner = corner_id;
            best_plans[corner_id].D = D;
            best_plans[corner_id].area = area;
            best_plans[corner_id].score = score;
        }
    }
}

bool diag_plans_overlap(int corner_a, int D_a, int corner_b, int D_b) {
    // Check if any cell is in both safe zones
    // Opposite corners (TL-BR, TR-BL) never overlap for reasonable D
    if ((corner_a == 0 && corner_b == 3) || (corner_a == 3 && corner_b == 0)) return false;
    if ((corner_a == 1 && corner_b == 2) || (corner_a == 2 && corner_b == 1)) return false;

    // Adjacent corners overlap if D_a + D_b > 32
    // Also check wall overlap
    if (D_a + D_b > 32) return true;

    // Check if walls overlap with each other's safe zones
    auto walls_a = get_diag_wall_cells(corner_a, D_a);
    for (auto& wc : walls_a) {
        if (is_in_safe_zone(corner_b, D_b, wc.r, wc.c)) return true;
    }
    auto walls_b = get_diag_wall_cells(corner_b, D_b);
    for (auto& wc : walls_b) {
        if (is_in_safe_zone(corner_a, D_a, wc.r, wc.c)) return true;
    }

    return false;
}

void choose_strategy() {
    for (int i = 0; i < 4; i++) {
        evaluate_corner(i);
    }

    // Try all pairs
    double best_pair_score = -1;
    int best_pair[2] = {0, 3};

    for (int a = 0; a < 4; a++) {
        if (best_plans[a].score <= 0) continue;
        for (int b = a + 1; b < 4; b++) {
            if (best_plans[b].score <= 0) continue;
            if (diag_plans_overlap(a, best_plans[a].D, b, best_plans[b].D)) continue;
            double combined = best_plans[a].score + best_plans[b].score;
            if (combined > best_pair_score) {
                best_pair_score = combined;
                best_pair[0] = a;
                best_pair[1] = b;
            }
        }
    }

    // Try triples
    double best_triple_score = -1;
    int best_triple[3] = {-1, -1, -1};

    for (int a = 0; a < 4; a++) {
        if (best_plans[a].score <= 0) continue;
        for (int b = a + 1; b < 4; b++) {
            if (best_plans[b].score <= 0) continue;
            if (diag_plans_overlap(a, best_plans[a].D, b, best_plans[b].D)) continue;
            for (int c2 = b + 1; c2 < 4; c2++) {
                if (best_plans[c2].score <= 0) continue;
                if (diag_plans_overlap(a, best_plans[a].D, c2, best_plans[c2].D)) continue;
                if (diag_plans_overlap(b, best_plans[b].D, c2, best_plans[c2].D)) continue;
                double combined = best_plans[a].score + best_plans[b].score + best_plans[c2].score;
                if (combined > best_triple_score) {
                    best_triple_score = combined;
                    best_triple[0] = a;
                    best_triple[1] = b;
                    best_triple[2] = c2;
                }
            }
        }
    }

    // Best single
    double best_single_score = -1;
    int best_single = 0;
    for (int i = 0; i < 4; i++) {
        if (best_plans[i].score > best_single_score) {
            best_single_score = best_plans[i].score;
            best_single = i;
        }
    }

    // Choose: give bonuses for faster construction
    double single_effective = best_single_score * 1.4;
    double pair_effective = best_pair_score * 1.1;
    double triple_effective = best_triple_score * 0.95;

    if (best_triple_score > 0 && triple_effective > pair_effective && triple_effective > single_effective && M >= 6) {
        num_active_plans = 3;
        active_plans[0] = best_plans[best_triple[0]];
        active_plans[1] = best_plans[best_triple[1]];
        active_plans[2] = best_plans[best_triple[2]];
    } else if (best_pair_score > 0 && pair_effective > single_effective) {
        num_active_plans = 2;
        active_plans[0] = best_plans[best_pair[0]];
        active_plans[1] = best_plans[best_pair[1]];
    } else {
        num_active_plans = 1;
        active_plans[0] = best_plans[best_single];
    }
}

void assign_humans() {
    if (num_active_plans == 1) {
        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
        return;
    }

    if (num_active_plans == 2) {
        int count0 = M / 2;
        std::vector<std::pair<double, int>> preference(M);
        for (int i = 0; i < M; i++) {
            double d0 = corner_dist(active_plans[0].corner, humans[i].r, humans[i].c);
            double d1 = corner_dist(active_plans[1].corner, humans[i].r, humans[i].c);
            preference[i] = {d0 - d1, i};
        }
        std::sort(preference.begin(), preference.end());
        int assigned0 = 0;
        for (auto& [pref, idx] : preference) {
            if (assigned0 < count0) {
                human_plan_assignment[idx] = 0;
                assigned0++;
            } else {
                human_plan_assignment[idx] = 1;
            }
        }
        return;
    }

    // 3 plans: distribute based on proximity
    // Assign each human to closest plan
    std::vector<std::pair<int,int>> assignments; // (plan, human)
    int plan_count[3] = {0, 0, 0};
    int min_per_plan = std::max(1, M / 3);

    // First pass: assign each to closest
    for (int i = 0; i < M; i++) {
        int best_p = 0;
        double best_d = 1e9;
        for (int p = 0; p < num_active_plans; p++) {
            double d = corner_dist(active_plans[p].corner, humans[i].r, humans[i].c);
            if (d < best_d) { best_d = d; best_p = p; }
        }
        human_plan_assignment[i] = best_p;
        plan_count[best_p]++;
    }

    // Rebalance: ensure each plan has at least 1 human
    for (int p = 0; p < num_active_plans; p++) {
        if (plan_count[p] == 0) {
            // Steal from the plan with most humans
            int max_p = 0;
            for (int q = 1; q < num_active_plans; q++) {
                if (plan_count[q] > plan_count[max_p]) max_p = q;
            }
            // Find the human in max_p closest to plan p
            int best_h = -1;
            double best_d = 1e9;
            for (int i = 0; i < M; i++) {
                if (human_plan_assignment[i] == max_p) {
                    double d = corner_dist(active_plans[p].corner, humans[i].r, humans[i].c);
                    if (d < best_d) { best_d = d; best_h = i; }
                }
            }
            if (best_h >= 0) {
                human_plan_assignment[best_h] = p;
                plan_count[max_p]--;
                plan_count[p]++;
            }
        }
    }
}

// Build order: from both ends toward middle ("closing jaw")
std::vector<int> get_build_order(int num_cells) {
    std::vector<int> order;
    int lo = 0, hi = num_cells - 1;
    bool from_lo = true;
    while (lo <= hi) {
        if (from_lo) {
            order.push_back(lo++);
        } else {
            order.push_back(hi--);
        }
        from_lo = !from_lo;
    }
    return order;
}

