        int assigned0 = 0;
        for (auto& [pref, idx] : preference) {
            if (assigned0 < count0) {
                human_plan_assignment[idx] = 0;
                assigned0++;
            } else {
                human_plan_assignment[idx] = 1;
            }
        }
        return;
    }

    // 3 plans: distribute based on proximity
    // Assign each human to closest plan
    std::vector<std::pair<int,int>> assignments; // (plan, human)
    int plan_count[3] = {0, 0, 0};
    int min_per_plan = std::max(1, M / 3);

    // First pass: assign each to closest
    for (int i = 0; i < M; i++) {
        int best_p = 0;
        double best_d = 1e9;
        for (int p = 0; p < num_active_plans; p++) {
            double d = corner_dist(active_plans[p].corner, humans[i].r, humans[i].c);
            if (d < best_d) { best_d = d; best_p = p; }
        }
        human_plan_assignment[i] = best_p;
        plan_count[best_p]++;
    }

    // Rebalance: ensure each plan has at least 1 human
    for (int p = 0; p < num_active_plans; p++) {
        if (plan_count[p] == 0) {
            // Steal from the plan with most humans
            int max_p = 0;
            for (int q = 1; q < num_active_plans; q++) {
                if (plan_count[q] > plan_count[max_p]) max_p = q;
            }
            // Find the human in max_p closest to plan p
            int best_h = -1;
            double best_d = 1e9;
            for (int i = 0; i < M; i++) {
                if (human_plan_assignment[i] == max_p) {
                    double d = corner_dist(active_plans[p].corner, humans[i].r, humans[i].c);
                    if (d < best_d) { best_d = d; best_h = i; }
                }
            }
            if (best_h >= 0) {
                human_plan_assignment[best_h] = p;
                plan_count[max_p]--;
                plan_count[p]++;
            }
        }
    }
}

// Build order: from both ends toward middle ("closing jaw")
std::vector<int> get_build_order(int num_cells) {
    std::vector<int> order;
    int lo = 0, hi = num_cells - 1;
    bool from_lo = true;
    while (lo <= hi) {
        if (from_lo) {
            order.push_back(lo++);
        } else {
            order.push_back(hi--);
        }
        from_lo = !from_lo;
    }
    return order;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();

    for (int p = 0; p < num_active_plans; p++) {
        plan_walls[p] = get_diag_wall_cells(active_plans[p].corner, active_plans[p].D);
    }
    assign_humans();

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        for (int i = 0; i < M; i++) {
            int my_plan = human_plan_assignment[i];
            auto& my_walls = plan_walls[my_plan];
            auto& plan = active_plans[my_plan];

            // Find best unbuilt wall cell: prioritize from ends (closing jaw pattern)
            // and proximity to human
            int best_idx = -1;
            int best_priority = INF;

            for (int w = 0; w < (int)my_walls.size(); w++) {
                Point wc = my_walls[w];
                if (grid[wc.r][wc.c]) continue;

                bool claimed = false;
                for (auto& wb : walls_being_built) {
                    if (wb == wc) { claimed = true; break; }
                }
                if (claimed) continue;

                int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                // Priority based on distance from ends (prefer end cells for early sealing)
                int end_dist = std::min(w, (int)my_walls.size() - 1 - w);
                // Combined: primarily by human distance, with bias toward end cells
                int priority = dist * 3 + end_dist;
                if (priority < best_priority) {
                    best_priority = priority;
                    best_idx = w;
                }
            }

            if (best_idx == -1) {
                // All walls built - move into safe zone
                // Find center of safe zone
                int corner = plan.corner;
                int D = plan.D;
                Point target = {-1, -1};

                // Try center of the triangle
                if (corner == 0) target = {D/3, D/3};
                else if (corner == 1) target = {D/3, 30 - D/3 + 1};
                else if (corner == 2) target = {30 - D/3 + 1, D/3};
                else target = {30 - D/3 + 1, 30 - D/3 + 1};

                if (!valid(target.r, target.c) || !passable(target.r, target.c) ||
