                    bool found = false;
                    for (int r = 1; r <= GRID_SIZE && !found; r++) {
                        for (int c = 1; c <= GRID_SIZE && !found; c++) {
                            if (passable(r, c) && is_in_safe_zone(corner, D, r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                    if (!found) { actions[i] = '.'; continue; }
