# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Pet speed lookup (moves per turn)
int pet_speed(int type) {
    if (type == 1) return 1; // cow
    if (type == 2) return 2; // pig
    if (type == 3) return 3; // rabbit
    if (type == 4) return 2; // dog (1 toward + 1 basic)
    return 2; // cat (1 toward + 1 basic)
}

struct CornerPlan {
    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
    int wall_row;
    int wall_col;
    int area;
    int cost;
    int pets_inside;
    double score;
    int r_min, r_max, c_min, c_max;
};

std::vector<Point> get_wall_cells(const CornerPlan& plan) {
    std::vector<Point> cells;
    if (plan.corner == 0) {
        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
    } else if (plan.corner == 1) {
        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
    } else if (plan.corner == 2) {
        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
    } else {
        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
    }
    return cells;
}

bool is_safe_side(const CornerPlan& plan, int r, int c) {
    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
}

CornerPlan plans[2];
int num_plans;

void find_best_corner(int corner_id, CornerPlan& best) {
    best.score = -1;

    for (int wr = 2; wr <= 29; wr++) {
        for (int wc = 2; wc <= 29; wc++) {
            int pets_inside = 0;
            int r_min, r_max, c_min, c_max;
            int cost;

            if (corner_id == 0) {
                r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
                cost = wc + (wr - 1);
            } else if (corner_id == 1) {
                r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
                cost = (GRID_SIZE - wc + 1) + (wr - 1);
            } else if (corner_id == 2) {
                r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
                cost = wc + (GRID_SIZE - wr);
            } else {
                r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
                cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
            }

            int area = (r_max - r_min + 1) * (c_max - c_min + 1);
            if (area < 50) continue;
            if (cost > 40) continue;

            int pets_near = 0;
            for (auto& p : pets) {
                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
                    pets_inside++;
                }
                bool on_h_wall = (p.r == wr && ((corner_id <= 1 && p.c >= 1 && p.c <= wc) ||
                                                (corner_id == 0 && p.c >= 1 && p.c <= wc) ||
                                                (corner_id == 1 && p.c >= wc && p.c <= GRID_SIZE) ||
                                                (corner_id == 2 && p.c >= 1 && p.c <= wc) ||
                                                (corner_id == 3 && p.c >= wc && p.c <= GRID_SIZE)));
                bool on_v_wall = (p.c == wc && ((corner_id == 0 && p.r >= 1 && p.r < wr) ||
                                                (corner_id == 1 && p.r >= 1 && p.r < wr) ||
                                                (corner_id == 2 && p.r > wr && p.r <= GRID_SIZE) ||
                                                (corner_id == 3 && p.r > wr && p.r <= GRID_SIZE)));
                if (on_h_wall || on_v_wall) pets_near++;
            }

            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
            double time_factor = 1.0 / (1.0 + cost * 0.01);
            double pet_bonus = (pets_inside == 0) ? 2.0 : std::pow(0.7, pets_inside);
            double near_penalty = 1.0 / (1.0 + pets_near * 0.1);

            double avg_human_dist = 0;
            for (int hi = 0; hi < M; hi++) {
                int dr = 0, dc = 0;
                if (humans[hi].r < r_min) dr = r_min - humans[hi].r;
                else if (humans[hi].r > r_max) dr = humans[hi].r - r_max;
                if (humans[hi].c < c_min) dc = c_min - humans[hi].c;
                else if (humans[hi].c > c_max) dc = humans[hi].c - c_max;
                avg_human_dist += dr + dc;
            }
            avg_human_dist /= M;
            double dist_factor = 1.0 / (1.0 + avg_human_dist * 0.02);

            double score = base_score * time_factor * pet_bonus * dist_factor * near_penalty;

            if (score > best.score) {
                best.corner = corner_id;
                best.wall_row = wr;
                best.wall_col = wc;
                best.area = area;
                best.cost = cost;
                best.pets_inside = pets_inside;
                best.score = score;
                best.r_min = r_min;
                best.r_max = r_max;
                best.c_min = c_min;
                best.c_max = c_max;
            }
        }
    }
}

double compute_dual_wall_score(int tr, int br) {
    int pets_above = 0, pets_below = 0;
    for (auto& p : pets) {
        if (p.r < tr) pets_above++;
        else if (p.r > br) pets_below++;
    }
    int area_above = (tr - 1) * GRID_SIZE;
    int area_below = (GRID_SIZE - br) * GRID_SIZE;
    double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
    double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
    return (sa + sb) / 2.0;
}

int strategy_mode;
int dual_wall_top, dual_wall_bot;

void choose_strategy() {
    CornerPlan corners[4];
    for (int i = 0; i < 4; i++) {
        find_best_corner(i, corners[i]);
    }

    double best_pair_score = -1;
    int best_pair[2] = {0, 3};

    for (int a = 0; a < 4; a++) {
        for (int b = a + 1; b < 4; b++) {
            int r_min_a = corners[a].r_min, r_max_a = corners[a].r_max;
            int c_min_a = corners[a].c_min, c_max_a = corners[a].c_max;
            int r_min_b = corners[b].r_min, r_max_b = corners[b].r_max;
            int c_min_b = corners[b].c_min, c_max_b = corners[b].c_max;

            bool regions_overlap = !(r_max_a < r_min_b || r_max_b < r_min_a ||
                                    c_max_a < c_min_b || c_max_b < c_min_a);
            if (regions_overlap) continue;

            double combined = corners[a].score + corners[b].score;
            if (combined > best_pair_score) {
                best_pair_score = combined;
                best_pair[0] = a;
                best_pair[1] = b;
            }
        }
    }

    double best_single_score = -1;
    int best_single = 0;
    for (int i = 0; i < 4; i++) {
        if (corners[i].score > best_single_score) {
            best_single_score = corners[i].score;
            best_single = i;
        }
    }

    double best_dual_h = -1;
    int best_tr = 8, best_br = 23;
    for (int tr = 3; tr <= 15; tr++) {
        for (int br = tr + 4; br <= 28; br++) {
            double s = compute_dual_wall_score(tr, br);
            if (s > best_dual_h) {
                best_dual_h = s;
                best_tr = tr;
                best_br = br;
            }
        }
    }

    double l_pair_effective = best_pair_score * 1.2;
    double l_single_effective = best_single_score * 1.3;

    if (l_pair_effective > best_dual_h && l_pair_effective > l_single_effective) {
        strategy_mode = 0;
        num_plans = 2;
        plans[0] = corners[best_pair[0]];
        plans[1] = corners[best_pair[1]];
    } else if (l_single_effective > best_dual_h) {
        strategy_mode = 0;
        num_plans = 1;
        plans[0] = corners[best_single];
    } else {
        strategy_mode = 1;
        dual_wall_top = best_tr;
        dual_wall_bot = best_br;
    }
}

int human_plan_assignment[10];
std::vector<Point> plan_walls[2];

void assign_humans_lshape() {
    if (num_plans == 1) {
        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
        return;
    }

    int count0 = M / 2;
    std::vector<std::pair<double, int>> preference(M);
    for (int i = 0; i < M; i++) {
        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);

        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);

        preference[i] = {d0 - d1, i};
    }
    std::sort(preference.begin(), preference.end());

    int assigned0 = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned0 < count0) {
            human_plan_assignment[idx] = 0;
            assigned0++;
        } else {
            human_plan_assignment[idx] = 1;
        }
    }
}

int human_wall_assignment_h[10];

void assign_humans_dual_h() {
    int top_count = M / 2;
    std::vector<std::pair<int, int>> preference(M);
    for (int i = 0; i < M; i++) {
        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
    }
    std::sort(preference.begin(), preference.end());
    int assigned_top = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned_top < top_count) {
            human_wall_assignment_h[idx] = 0;
            assigned_top++;
        } else {
            human_wall_assignment_h[idx] = 1;
        }
    }
}

// Compute urgency for an unbuilt wall cell based on nearby pet threats
// Returns a penalty score (higher = more urgent to build)
double compute_gap_urgency(Point gap, int plan_idx) {
    double urgency = 0;
    auto& plan = plans[plan_idx];

    for (int pi = 0; pi < N; pi++) {
        // Distance from pet to the gap
        int dist = std::abs(pets[pi].r - gap.r) + std::abs(pets[pi].c - gap.c);
        int speed = pet_speed(pet_types[pi]);

        // How many turns until the pet could reach this gap
        int turns_to_reach = dist / speed;

        // Only care about pets on the UNSAFE side that could enter through this gap
        bool pet_on_unsafe_side = !is_safe_side(plan, pets[pi].r, pets[pi].c);

        if (pet_on_unsafe_side && turns_to_reach < 15) {
            // Urgency increases for faster/closer pets
            urgency += (double)speed / (1.0 + dist);
        }
    }
    return urgency;
}

// Check if a wall gap could allow a pet to reach the safe zone
bool is_critical_gap(Point gap, int plan_idx) {
    auto& plan = plans[plan_idx];
    // A gap is critical if a pet on the unsafe side is within 3 cells
    for (int pi = 0; pi < N; pi++) {
        if (is_safe_side(plan, pets[pi].r, pets[pi].c)) continue;
        int dist = std::abs(pets[pi].r - gap.r) + std::abs(pets[pi].c - gap.c);
        if (dist <= 3) return true;
    }
    return false;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();

    if (strategy_mode == 0) {
        for (int p = 0; p < num_plans; p++) {
            plan_walls[p] = get_wall_cells(plans[p]);
        }
        assign_humans_lshape();
    } else {
        assign_humans_dual_h();
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        if (strategy_mode == 0) {
            for (int i = 0; i < M; i++) {
                int my_plan = human_plan_assignment[i];
                auto& my_walls = plan_walls[my_plan];
                auto& plan = plans[my_plan];

                int corner_r = plan.wall_row;
                int corner_c = plan.wall_col;

                // Dynamic priority: combine corner distance, human distance, and pet urgency
                int best_idx = -1;
                double best_priority = 1e18;

                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int human_dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    int cdist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);

                    // Pet urgency: higher urgency means we should build this gap sooner
                    double urgency = compute_gap_urgency(wc, my_plan);

                    // Priority formula: lower is better
                    // - Human distance (need to reach it)
                    // - Corner distance (build from corner outward for incremental sealing)
                    // - Urgency bonus (subtract to prioritize urgent gaps)
                    double priority = (double)human_dist * 2.0 + (double)cdist * 1.0 - urgency * 8.0;

                    if (priority < best_priority) {
                        best_priority = priority;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
                    // All walls built - move to center of safe zone
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        bool found = false;
                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
                                if (passable(r, c)) {
                                    target = {r, c};
                                    found = true;
                                }
                            }
                        }
                    }
                    if (humans[i] != target) {
                        actions[i] = move_toward(humans[i], target);
                    }
                } else {
                    Point wall_target = my_walls[best_idx];

                    // Find standing position: prefer safe side
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;

                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;

                        bool in_safe = is_safe_side(plan, sr, sc);
                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        int effective_dist = in_safe ? dist : dist + 100;

                        if (effective_dist < best_stand_dist) {
                            best_stand_dist = effective_dist;
                            stand_pos = {sr, sc};
                        }
                    }

                    if (stand_pos.r == -1) {
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d];
                            int sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) {
                                stand_pos = {sr, sc};
                                break;
                            }
                        }
                    }

                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wall_target);
                                    break;
                                }
                            }
                        } else {
                            // Pet blocking - try nearby urgent alternative
                            bool built_alt = false;

                            // Sort alternatives by urgency
                            std::vector<std::pair<double, int>> alt_options;
                            for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
                                if (w2 == best_idx) continue;
                                Point wc2 = my_walls[w2];
                                if (grid[wc2.r][wc2.c]) continue;
                                if (!can_build_wall(wc2.r, wc2.c)) continue;

                                bool adjacent = false;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true;
                                        break;
                                    }
                                }
                                if (adjacent) {
                                    double u = compute_gap_urgency(wc2, my_plan);
                                    alt_options.push_back({-u, w2}); // negative for sorting (higher urgency first)
                                }
                            }

                            std::sort(alt_options.begin(), alt_options.end());

                            for (auto& [_, w2] : alt_options) {
                                Point wc2 = my_walls[w2];
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back(wc2);
                                        built_alt = true;
                                        break;
                                    }
                                }
                                if (built_alt) break;
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        } else {
            // Dual horizontal wall strategy (fallback)
            bool col_claimed_top[GRID_SIZE + 2], col_claimed_bot[GRID_SIZE + 2];
            memset(col_claimed_top, false, sizeof(col_claimed_top));
            memset(col_claimed_bot, false, sizeof(col_claimed_bot));

            for (int i = 0; i < M; i++) {
                int my_wall_row = (human_wall_assignment_h[i] == 0) ? dual_wall_top : dual_wall_bot;
                bool* my_claimed = (human_wall_assignment_h[i] == 0) ? col_claimed_top : col_claimed_bot;

                bool wall_done = true;
                for (int c = 1; c <= GRID_SIZE; c++) {
                    if (!grid[my_wall_row][c]) { wall_done = false; break; }
                }

                if (wall_done) {
                    int safe_r;
                    if (human_wall_assignment_h[i] == 0) {
                        safe_r = std::max(1, dual_wall_top / 2);
                    } else {
                        safe_r = std::min(GRID_SIZE, dual_wall_bot + (GRID_SIZE - dual_wall_bot) / 2);
                    }
                    Point target = {safe_r, GRID_SIZE / 2};
                    if (!passable(target.r, target.c)) {
                        int s, e;
                        if (human_wall_assignment_h[i] == 0) { s = 1; e = dual_wall_top - 1; }
                        else { s = dual_wall_bot + 1; e = GRID_SIZE; }
                        for (int r = s; r <= e; r++) {
                            for (int c = 1; c <= GRID_SIZE; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_target; }
                            }
                        }
                        found_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    int target_col = -1;
                    int min_dist = INF;
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (grid[my_wall_row][c] || my_claimed[c]) continue;
                        int dist = std::abs(humans[i].r - my_wall_row) + std::abs(humans[i].c - c);
                        if (dist < min_dist) { min_dist = dist; target_col = c; }
                    }

                    if (target_col == -1) {
                        actions[i] = '.';
                    } else {
                        my_claimed[target_col] = true;
                        int stand_r = (human_wall_assignment_h[i] == 0) ? my_wall_row - 1 : my_wall_row + 1;
                        Point stand_pos = {stand_r, target_col};

                        if (!passable(stand_r, target_col)) {
                            int alts[4][2] = {{my_wall_row-1,target_col},{my_wall_row+1,target_col},
                                              {my_wall_row,target_col-1},{my_wall_row,target_col+1}};
                            bool found = false;
                            for (auto& a : alts) {
                                if (passable(a[0], a[1])) { stand_pos = {a[0], a[1]}; found = true; break; }
                            }
                            if (!found) { actions[i] = '.'; continue; }
                        }

                        if (humans[i] == stand_pos) {
                            if (can_build_wall(my_wall_row, target_col)) {
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == my_wall_row && humans[i].c + DC[d] == target_col) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back({my_wall_row, target_col});
                                        break;
                                    }
                                }
                            } else {
                                my_claimed[target_col] = false;
                                actions[i] = '.';
                            }
                        } else {
                            actions[i] = move_toward(humans[i], stand_pos);
                        }
                    }
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
