# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

struct CornerPlan {
    int corner;
    int wall_row;
    int wall_col;
    int area;
    int cost;
    int pets_inside;
    double score;
    int r_min, r_max, c_min, c_max;
};

// Generate wall cells in contiguous build order from the corner intersection outward
// This ensures at every point the built subset + grid boundary seals the zone
std::vector<Point> get_wall_cells_contiguous(const CornerPlan& plan) {
    std::vector<Point> cells;
    int wr = plan.wall_row;
    int wc = plan.wall_col;

    // Start at intersection and build outward in both directions simultaneously
    // The intersection point is (wr, wc) - build it first
    cells.push_back({wr, wc});

    // Interleave horizontal and vertical extensions from the intersection
    int h_count, v_count;
    int h_dir, v_dir;

    if (plan.corner == 0) {
        // TL: horizontal goes left (wc-1 to 1), vertical goes up (wr-1 to 1)
        h_count = wc - 1; v_count = wr - 1;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc - step});
            if (step <= v_count) cells.push_back({wr - step, wc});
        }
    } else if (plan.corner == 1) {
        // TR: horizontal goes right (wc+1 to 30), vertical goes up (wr-1 to 1)
        h_count = GRID_SIZE - wc; v_count = wr - 1;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc + step});
            if (step <= v_count) cells.push_back({wr - step, wc});
        }
    } else if (plan.corner == 2) {
        // BL: horizontal goes left (wc-1 to 1), vertical goes down (wr+1 to 30)
        h_count = wc - 1; v_count = GRID_SIZE - wr;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc - step});
            if (step <= v_count) cells.push_back({wr + step, wc});
        }
    } else {
        // BR: horizontal goes right (wc+1 to 30), vertical goes down (wr+1 to 30)
        h_count = GRID_SIZE - wc; v_count = GRID_SIZE - wr;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc + step});
            if (step <= v_count) cells.push_back({wr + step, wc});
        }
    }

    return cells;
}

bool is_safe_side(const CornerPlan& plan, int r, int c) {
    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
}

CornerPlan best_plan;

void find_best_single_corner() {
    best_plan.score = -1;

    for (int corner_id = 0; corner_id < 4; corner_id++) {
        for (int wr = 2; wr <= 29; wr++) {
            for (int wc = 2; wc <= 29; wc++) {
                int pets_inside = 0;
                int r_min, r_max, c_min, c_max;
                int cost;

                if (corner_id == 0) {
                    r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
                    cost = wc + (wr - 1);
                } else if (corner_id == 1) {
                    r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
                    cost = (GRID_SIZE - wc + 1) + (wr - 1);
                } else if (corner_id == 2) {
                    r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
                    cost = wc + (GRID_SIZE - wr);
                } else {
                    r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
                    cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
                }

                int area = (r_max - r_min + 1) * (c_max - c_min + 1);
                if (area < 30) continue;
                if (cost > 50) continue;

                int pets_near = 0;
                for (auto& p : pets) {
                    if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
                        pets_inside++;
                    }
                    // Count pets on the wall boundary
                    bool on_wall = false;
                    if (corner_id == 0) {
                        on_wall = (p.r == wr && p.c >= 1 && p.c <= wc) ||
                                  (p.c == wc && p.r >= 1 && p.r < wr);
                    } else if (corner_id == 1) {
                        on_wall = (p.r == wr && p.c >= wc && p.c <= GRID_SIZE) ||
                                  (p.c == wc && p.r >= 1 && p.r < wr);
                    } else if (corner_id == 2) {
                        on_wall = (p.r == wr && p.c >= 1 && p.c <= wc) ||
                                  (p.c == wc && p.r > wr && p.r <= GRID_SIZE);
                    } else {
                        on_wall = (p.r == wr && p.c >= wc && p.c <= GRID_SIZE) ||
                                  (p.c == wc && p.r > wr && p.r <= GRID_SIZE);
                    }
                    if (on_wall) pets_near++;
                }

                // Score: area matters a lot since all humans share the same zone
                // The key is area/900 * 2^(-pets_inside)
                // With all M humans in one zone, score = area/900 * 2^(-pets)
                double expected_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);

                // Penalize by cost (build time relative to M humans available)
                double build_time = (double)cost / M; // approximate turns to build
                double time_factor = 1.0 / (1.0 + build_time * 0.03);

                double pet_bonus = (pets_inside == 0) ? 1.5 : std::pow(0.5, pets_inside);
                double near_penalty = 1.0 / (1.0 + pets_near * 0.15);

                // Human distance matters less since ALL humans go to same zone
                double max_human_dist = 0;
                for (int hi = 0; hi < M; hi++) {
                    int dr = 0, dc = 0;
                    if (humans[hi].r < r_min) dr = r_min - humans[hi].r;
                    else if (humans[hi].r > r_max) dr = humans[hi].r - r_max;
                    if (humans[hi].c < c_min) dc = c_min - humans[hi].c;
                    else if (humans[hi].c > c_max) dc = humans[hi].c - c_max;
                    max_human_dist = std::max(max_human_dist, (double)(dr + dc));
                }
                double dist_factor = 1.0 / (1.0 + max_human_dist * 0.01);

                double score = expected_score * time_factor * pet_bonus * dist_factor * near_penalty;

                if (score > best_plan.score) {
                    best_plan.corner = corner_id;
                    best_plan.wall_row = wr;
                    best_plan.wall_col = wc;
                    best_plan.area = area;
                    best_plan.cost = cost;
                    best_plan.pets_inside = pets_inside;
                    best_plan.score = score;
                    best_plan.r_min = r_min;
                    best_plan.r_max = r_max;
                    best_plan.c_min = c_min;
                    best_plan.c_max = c_max;
                }
            }
        }
    }
}

// Also evaluate dual-corner as fallback
CornerPlan dual_plans[2];
int num_plans; // 1 = single zone, 2 = dual zone
CornerPlan active_plans[2];

void find_dual_corners() {
    CornerPlan corners[4];
    for (int corner_id = 0; corner_id < 4; corner_id++) {
        corners[corner_id].score = -1;
        for (int wr = 2; wr <= 29; wr++) {
            for (int wc = 2; wc <= 29; wc++) {
                int pets_inside = 0;
                int r_min, r_max, c_min, c_max;
                int cost;

                if (corner_id == 0) {
                    r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
                    cost = wc + (wr - 1);
                } else if (corner_id == 1) {
                    r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
                    cost = (GRID_SIZE - wc + 1) + (wr - 1);
                } else if (corner_id == 2) {
                    r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
                    cost = wc + (GRID_SIZE - wr);
                } else {
                    r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
                    cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
                }

                int area = (r_max - r_min + 1) * (c_max - c_min + 1);
                if (area < 50) continue;
                if (cost > 40) continue;

                int pets_near = 0;
                for (auto& p : pets) {
                    if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
                        pets_inside++;
                    }
                    bool on_wall = false;
                    if (corner_id == 0) {
                        on_wall = (p.r == wr && p.c >= 1 && p.c <= wc) ||
                                  (p.c == wc && p.r >= 1 && p.r < wr);
                    } else if (corner_id == 1) {
                        on_wall = (p.r == wr && p.c >= wc && p.c <= GRID_SIZE) ||
                                  (p.c == wc && p.r >= 1 && p.r < wr);
                    } else if (corner_id == 2) {
                        on_wall = (p.r == wr && p.c >= 1 && p.c <= wc) ||
                                  (p.c == wc && p.r > wr && p.r <= GRID_SIZE);
                    } else {
                        on_wall = (p.r == wr && p.c >= wc && p.c <= GRID_SIZE) ||
                                  (p.c == wc && p.r > wr && p.r <= GRID_SIZE);
                    }
                    if (on_wall) pets_near++;
                }

                double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
                double time_factor = 1.0 / (1.0 + cost * 0.01);
                double pet_bonus = (pets_inside == 0) ? 2.0 : std::pow(0.7, pets_inside);
                double near_penalty = 1.0 / (1.0 + pets_near * 0.1);

                double avg_human_dist = 0;
                for (int hi = 0; hi < M; hi++) {
                    int dr = 0, dc = 0;
                    if (humans[hi].r < r_min) dr = r_min - humans[hi].r;
                    else if (humans[hi].r > r_max) dr = humans[hi].r - r_max;
                    if (humans[hi].c < c_min) dc = c_min - humans[hi].c;
                    else if (humans[hi].c > c_max) dc = humans[hi].c - c_max;
                    avg_human_dist += dr + dc;
                }
                avg_human_dist /= M;
                double dist_factor = 1.0 / (1.0 + avg_human_dist * 0.02);

                double score = base_score * time_factor * pet_bonus * dist_factor * near_penalty;

                if (score > corners[corner_id].score) {
                    corners[corner_id].corner = corner_id;
                    corners[corner_id].wall_row = wr;
                    corners[corner_id].wall_col = wc;
                    corners[corner_id].area = area;
                    corners[corner_id].cost = cost;
                    corners[corner_id].pets_inside = pets_inside;
                    corners[corner_id].score = score;
                    corners[corner_id].r_min = r_min;
                    corners[corner_id].r_max = r_max;
                    corners[corner_id].c_min = c_min;
                    corners[corner_id].c_max = c_max;
                }
            }
        }
    }

    double best_pair_score = -1;
    int best_pair[2] = {0, 3};
    for (int a = 0; a < 4; a++) {
        if (corners[a].score <= 0) continue;
        for (int b = a + 1; b < 4; b++) {
            if (corners[b].score <= 0) continue;
            bool regions_overlap = !(corners[a].r_max < corners[b].r_min || corners[b].r_max < corners[a].r_min ||
                                    corners[a].c_max < corners[b].c_min || corners[b].c_max < corners[a].c_min);
            if (regions_overlap) continue;
            double combined = corners[a].score + corners[b].score;
            if (combined > best_pair_score) {
                best_pair_score = combined;
                best_pair[0] = a;
                best_pair[1] = b;
            }
        }
    }

    if (best_pair_score > 0) {
        dual_plans[0] = corners[best_pair[0]];
        dual_plans[1] = corners[best_pair[1]];
    }
}

void choose_strategy() {
    find_best_single_corner();
    find_dual_corners();

    // Compare single large zone (all humans) vs dual zones (split humans)
    // Single zone: all M humans get area/900 * 2^(-pets)
    // Dual zone: M/2 humans get area1/900 * 2^(-pets1), M/2 get area2/900 * 2^(-pets2)
    // Average satisfaction:
    //   Single = single_area / 900 * 2^(-single_pets)
    //   Dual = (area1*2^(-pets1) + area2*2^(-pets2)) / (2*900)

    // But also factor in build reliability
    double single_expected = (double)best_plan.area / 900.0 * std::pow(2.0, -(double)best_plan.pets_inside);
    double dual_expected = ((double)dual_plans[0].area / 900.0 * std::pow(2.0, -(double)dual_plans[0].pets_inside) +
                           (double)dual_plans[1].area / 900.0 * std::pow(2.0, -(double)dual_plans[1].pets_inside)) / 2.0;

    // Single has advantage of faster build (all humans) and larger area benefit
    // Give single a boost for faster construction
    double single_build_turns = (double)best_plan.cost / M;
    double dual_build_turns = std::max((double)dual_plans[0].cost / (M/2.0), (double)dual_plans[1].cost / (M/2.0));

    double single_reliability = 1.0 / (1.0 + single_build_turns * 0.05);
    double dual_reliability = 1.0 / (1.0 + dual_build_turns * 0.05);

    double single_final = single_expected * single_reliability;
    double dual_final = dual_expected * dual_reliability;

    if (single_final >= dual_final) {
        num_plans = 1;
        active_plans[0] = best_plan;
    } else {
        num_plans = 2;
        active_plans[0] = dual_plans[0];
        active_plans[1] = dual_plans[1];
    }
}

int human_plan_assignment[10];
std::vector<Point> plan_walls[2];

void assign_humans() {
    if (num_plans == 1) {
        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
        return;
    }

    int count0 = M / 2;
    std::vector<std::pair<double, int>> preference(M);
    for (int i = 0; i < M; i++) {
        double cr0 = (active_plans[0].r_min + active_plans[0].r_max) / 2.0;
        double cc0 = (active_plans[0].c_min + active_plans[0].c_max) / 2.0;
        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);

        double cr1 = (active_plans[1].r_min + active_plans[1].r_max) / 2.0;
        double cc1 = (active_plans[1].c_min + active_plans[1].c_max) / 2.0;
        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);

        preference[i] = {d0 - d1, i};
    }
    std::sort(preference.begin(), preference.end());

    int assigned0 = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned0 < count0) {
            human_plan_assignment[idx] = 0;
            assigned0++;
        } else {
            human_plan_assignment[idx] = 1;
        }
    }
}

// Track which wall cells are built to enforce contiguous building
bool wall_built[100];

// Check if building cell at index w_idx maintains contiguity
// (it must be adjacent to an already-built cell or to the grid boundary on the safe side)
bool is_contiguous_buildable(int plan_idx, int w_idx) {
    auto& plan = active_plans[plan_idx];
    auto& walls = plan_walls[plan_idx];
    Point wc = walls[w_idx];

    // The intersection cell (index 0) is always buildable first
    if (w_idx == 0) return true;

    // Check if adjacent to any already-built wall cell
    for (int w2 = 0; w2 < (int)walls.size(); w2++) {
        if (!wall_built[w2]) continue;
        if (std::abs(walls[w2].r - wc.r) + std::abs(walls[w2].c - wc.c) == 1) return true;
    }

    // Check if adjacent to grid boundary of safe zone
    // (this means adjacent to the edge, which is always "sealed")
    if (plan.corner == 0 || plan.corner == 2) {
        if (wc.c == 1) return true; // left edge
    }
    if (plan.corner == 1 || plan.corner == 3) {
        if (wc.c == GRID_SIZE) return true; // right edge
    }
    if (plan.corner == 0 || plan.corner == 1) {
        if (wc.r == 1) return true; // top edge
    }
    if (plan.corner == 2 || plan.corner == 3) {
        if (wc.r == GRID_SIZE) return true; // bottom edge
    }

    return false;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();

    for (int p = 0; p < num_plans; p++) {
        plan_walls[p] = get_wall_cells_contiguous(active_plans[p]);
    }
    assign_humans();
    memset(wall_built, false, sizeof(wall_built));

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        for (int i = 0; i < M; i++) {
            int my_plan = human_plan_assignment[i];
            auto& my_walls = plan_walls[my_plan];
            auto& plan = active_plans[my_plan];

            // Find best unbuilt wall cell that maintains contiguity
            int best_idx = -1;
            int best_priority = INF;

            for (int w = 0; w < (int)my_walls.size(); w++) {
                Point wc = my_walls[w];
                if (grid[wc.r][wc.c]) continue;

                // Must maintain contiguous wall front
                if (!is_contiguous_buildable(my_plan, w)) continue;

                bool claimed = false;
                for (auto& wb : walls_being_built) {
                    if (wb == wc) { claimed = true; break; }
                }
                if (claimed) continue;

                int human_dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                // Build order index as tiebreaker (prefer earlier in contiguous order)
                int priority = human_dist * 3 + w;

                if (priority < best_priority) {
                    best_priority = priority;
                    best_idx = w;
                }
            }

            if (best_idx == -1) {
                // All contiguous-buildable cells are built - try any remaining
                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;
                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;
                    int human_dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    int priority = human_dist * 3 + w;
                    if (priority < best_priority) {
                        best_priority = priority;
                        best_idx = w;
                    }
                }
            }

            if (best_idx == -1) {
                // All walls built - move into safe zone
                int tr = (plan.r_min + plan.r_max) / 2;
                int tc = (plan.c_min + plan.c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c)) {
                    bool found = false;
                    for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
                        for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }
                if (humans[i] != target) {
                    actions[i] = move_toward(humans[i], target);
                }
            } else {
                Point wall_target = my_walls[best_idx];

                // Find standing position: prefer safe side
                Point stand_pos = {-1, -1};
                int best_stand_dist = INF;

                for (int d = 0; d < 4; d++) {
                    int sr = wall_target.r + DR[d];
                    int sc = wall_target.c + DC[d];
                    if (!passable(sr, sc)) continue;

                    bool in_safe = is_safe_side(plan, sr, sc);
                    int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                    int effective_dist = in_safe ? dist : dist + 100;

                    if (effective_dist < best_stand_dist) {
                        best_stand_dist = effective_dist;
                        stand_pos = {sr, sc};
                    }
                }

                if (stand_pos.r == -1) {
                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (passable(sr, sc)) {
                            stand_pos = {sr, sc};
                            break;
                        }
                    }
                }

                if (stand_pos.r == -1) {
                    actions[i] = '.';
                } else if (humans[i] == stand_pos) {
                    if (can_build_wall(wall_target.r, wall_target.c)) {
                        for (int d = 0; d < 4; d++) {
                            if (humans[i].r + DR[d] == wall_target.r &&
                                humans[i].c + DC[d] == wall_target.c) {
                                actions[i] = BUILD_CH[d];
                                walls_being_built.push_back(wall_target);
                                break;
                            }
                        }
                    } else {
                        // Pet blocking - try building another contiguous cell nearby
                        bool built_alt = false;
                        for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
                            if (w2 == best_idx) continue;
                            Point wc2 = my_walls[w2];
                            if (grid[wc2.r][wc2.c]) continue;
                            if (!can_build_wall(wc2.r, wc2.c)) continue;
                            if (!is_contiguous_buildable(my_plan, w2)) continue;

                            bool adjacent = false;
                            int build_dir = -1;
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                    adjacent = true;
                                    build_dir = d;
                                    break;
                                }
                            }
                            if (adjacent) {
