// Generate wall cells in contiguous build order from the corner intersection outward
// This ensures at every point the built subset + grid boundary seals the zone
std::vector<Point> get_wall_cells_contiguous(const CornerPlan& plan) {
    std::vector<Point> cells;
    int wr = plan.wall_row;
    int wc = plan.wall_col;

    // Start at intersection and build outward in both directions simultaneously
    // The intersection point is (wr, wc) - build it first
    cells.push_back({wr, wc});

    // Interleave horizontal and vertical extensions from the intersection
    int h_count, v_count;
    int h_dir, v_dir;

    if (plan.corner == 0) {
        // TL: horizontal goes left (wc-1 to 1), vertical goes up (wr-1 to 1)
        h_count = wc - 1; v_count = wr - 1;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc - step});
            if (step <= v_count) cells.push_back({wr - step, wc});
        }
    } else if (plan.corner == 1) {
        // TR: horizontal goes right (wc+1 to 30), vertical goes up (wr-1 to 1)
        h_count = GRID_SIZE - wc; v_count = wr - 1;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc + step});
            if (step <= v_count) cells.push_back({wr - step, wc});
        }
    } else if (plan.corner == 2) {
        // BL: horizontal goes left (wc-1 to 1), vertical goes down (wr+1 to 30)
        h_count = wc - 1; v_count = GRID_SIZE - wr;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc - step});
            if (step <= v_count) cells.push_back({wr + step, wc});
        }
    } else {
        // BR: horizontal goes right (wc+1 to 30), vertical goes down (wr+1 to 30)
        h_count = GRID_SIZE - wc; v_count = GRID_SIZE - wr;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc + step});
            if (step <= v_count) cells.push_back({wr + step, wc});
        }
    }

    return cells;
}

bool is_safe_side(const CornerPlan& plan, int r, int c) {
    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
