        } else {
            // All humans work on the current target plan
            auto& my_walls = plan_walls[target_plan];
            auto& plan = active_plans[target_plan];
            int corner_r = plan.wall_row;
            int corner_c = plan.wall_col;

            for (int i = 0; i < M; i++) {
                int best_idx = -1;
                int best_priority = INF;

                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    int cdist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);
                    int priority = dist * 2 + cdist;
                    if (priority < best_priority) {
