                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;

                        bool in_safe = is_safe_side(plan, sr, sc);
                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        int effective_dist = in_safe ? dist : dist + 100;

                        if (effective_dist < best_stand_dist) {
                            best_stand_dist = effective_dist;
                            stand_pos = {sr, sc};
                        }
                    }

                    if (stand_pos.r == -1) {
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d];
                            int sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) {
                                stand_pos = {sr, sc};
                                break;
                            }
                        }
                    }

                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wall_target);
                                    break;
                                }
                            }
                        } else {
                            bool built_alt = false;
                            for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
                                if (w2 == best_idx) continue;
                                Point wc2 = my_walls[w2];
                                if (grid[wc2.r][wc2.c]) continue;
                                if (!can_build_wall(wc2.r, wc2.c)) continue;

                                bool adjacent = false;
                                int build_dir = -1;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true;
                                        build_dir = d;
                                        break;
                                    }
                                }
                                if (adjacent) {
                                    actions[i] = BUILD_CH[build_dir];
                                    walls_being_built.push_back(wc2);
                                    built_alt = true;
                                    break;
                                }
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
