#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

struct CornerPlan {
    int corner;
    int wall_row;
    int wall_col;
    int area;
    int cost;
    int pets_inside;
    double score;
    int r_min, r_max, c_min, c_max;
};

std::vector<Point> get_wall_cells(const CornerPlan& plan) {
    std::vector<Point> cells;
    int wr = plan.wall_row;
    int wc = plan.wall_col;

    // Build from intersection outward (interleaved horizontal and vertical)
    cells.push_back({wr, wc});

    if (plan.corner == 0) {
        int h_count = wc - 1, v_count = wr - 1;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc - step});
            if (step <= v_count) cells.push_back({wr - step, wc});
        }
    } else if (plan.corner == 1) {
        int h_count = GRID_SIZE - wc, v_count = wr - 1;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc + step});
            if (step <= v_count) cells.push_back({wr - step, wc});
        }
    } else if (plan.corner == 2) {
        int h_count = wc - 1, v_count = GRID_SIZE - wr;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc - step});
            if (step <= v_count) cells.push_back({wr + step, wc});
        }
    } else {
        int h_count = GRID_SIZE - wc, v_count = GRID_SIZE - wr;
        for (int step = 1; step <= std::max(h_count, v_count); step++) {
            if (step <= h_count) cells.push_back({wr, wc + step});
            if (step <= v_count) cells.push_back({wr + step, wc});
        }
    }
    return cells;
}

bool is_safe_side(const CornerPlan& plan, int r, int c) {
    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
}

CornerPlan corners[4];
int num_plans;
CornerPlan active_plans[2];
int build_order[2]; // which plan to build first [0] then [1]
std::vector<Point> plan_walls[2];

void find_best_corner(int corner_id) {
    corners[corner_id].score = -1;

    for (int wr = 2; wr <= 29; wr++) {
        for (int wc = 2; wc <= 29; wc++) {
            int pets_inside = 0;
            int r_min, r_max, c_min, c_max;
            int cost;

            if (corner_id == 0) {
                r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
                cost = wc + (wr - 1);
            } else if (corner_id == 1) {
                r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
                cost = (GRID_SIZE - wc + 1) + (wr - 1);
            } else if (corner_id == 2) {
                r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
                cost = wc + (GRID_SIZE - wr);
            } else {
                r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
                cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
            }

            int area = (r_max - r_min + 1) * (c_max - c_min + 1);
            if (area < 50) continue;
            if (cost > 40) continue;

            int pets_near = 0;
            for (auto& p : pets) {
                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
                    pets_inside++;
                }
                bool on_wall = false;
                if (corner_id == 0) {
                    on_wall = (p.r == wr && p.c >= 1 && p.c <= wc) ||
                              (p.c == wc && p.r >= 1 && p.r < wr);
                } else if (corner_id == 1) {
                    on_wall = (p.r == wr && p.c >= wc && p.c <= GRID_SIZE) ||
                              (p.c == wc && p.r >= 1 && p.r < wr);
                } else if (corner_id == 2) {
                    on_wall = (p.r == wr && p.c >= 1 && p.c <= wc) ||
                              (p.c == wc && p.r > wr && p.r <= GRID_SIZE);
                } else {
                    on_wall = (p.r == wr && p.c >= wc && p.c <= GRID_SIZE) ||
                              (p.c == wc && p.r > wr && p.r <= GRID_SIZE);
                }
                if (on_wall) pets_near++;
            }

            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
            double time_factor = 1.0 / (1.0 + cost * 0.01);
            double pet_bonus = (pets_inside == 0) ? 2.0 : std::pow(0.7, pets_inside);
            double near_penalty = 1.0 / (1.0 + pets_near * 0.1);

            double avg_human_dist = 0;
            for (int hi = 0; hi < M; hi++) {
                int dr = 0, dc = 0;
                if (humans[hi].r < r_min) dr = r_min - humans[hi].r;
                else if (humans[hi].r > r_max) dr = humans[hi].r - r_max;
                if (humans[hi].c < c_min) dc = c_min - humans[hi].c;
                else if (humans[hi].c > c_max) dc = humans[hi].c - c_max;
                avg_human_dist += dr + dc;
            }
            avg_human_dist /= M;
            double dist_factor = 1.0 / (1.0 + avg_human_dist * 0.02);

            double score = base_score * time_factor * pet_bonus * dist_factor * near_penalty;

            if (score > corners[corner_id].score) {
                corners[corner_id].corner = corner_id;
                corners[corner_id].wall_row = wr;
                corners[corner_id].wall_col = wc;
                corners[corner_id].area = area;
                corners[corner_id].cost = cost;
                corners[corner_id].pets_inside = pets_inside;
                corners[corner_id].score = score;
                corners[corner_id].r_min = r_min;
                corners[corner_id].r_max = r_max;
                corners[corner_id].c_min = c_min;
                corners[corner_id].c_max = c_max;
            }
        }
    }
}

void choose_strategy() {
    for (int i = 0; i < 4; i++) {
        find_best_corner(i);
    }

    // Find best non-overlapping pair
    double best_pair_score = -1;
    int best_pair[2] = {0, 3};

    for (int a = 0; a < 4; a++) {
        if (corners[a].score <= 0) continue;
        for (int b = a + 1; b < 4; b++) {
            if (corners[b].score <= 0) continue;
            bool regions_overlap = !(corners[a].r_max < corners[b].r_min || corners[b].r_max < corners[a].r_min ||
                                    corners[a].c_max < corners[b].c_min || corners[b].c_max < corners[a].c_min);
            if (regions_overlap) continue;
            double combined = corners[a].score + corners[b].score;
            if (combined > best_pair_score) {
                best_pair_score = combined;
                best_pair[0] = a;
                best_pair[1] = b;
            }
        }
    }

    // Best single
    double best_single_score = -1;
    int best_single = 0;
    for (int i = 0; i < 4; i++) {
        if (corners[i].score > best_single_score) {
            best_single_score = corners[i].score;
            best_single = i;
        }
    }

    // Choose between pair and single
    double l_pair_effective = best_pair_score * 1.2;
    double l_single_effective = best_single_score * 1.3;

    if (l_pair_effective > l_single_effective) {
        num_plans = 2;
        active_plans[0] = corners[best_pair[0]];
        active_plans[1] = corners[best_pair[1]];

        // Decide build order: build the smaller/closer one first (faster to complete)
        // Then all humans move to second one
        double cost0 = active_plans[0].cost;
        double cost1 = active_plans[1].cost;
        // Factor in human proximity
        double avg_d0 = 0, avg_d1 = 0;
        for (int i = 0; i < M; i++) {
            int cr0 = (active_plans[0].r_min + active_plans[0].r_max) / 2;
            int cc0 = (active_plans[0].c_min + active_plans[0].c_max) / 2;
            avg_d0 += std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
            int cr1 = (active_plans[1].r_min + active_plans[1].r_max) / 2;
            int cc1 = (active_plans[1].c_min + active_plans[1].c_max) / 2;
            avg_d1 += std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
        }
        avg_d0 /= M; avg_d1 /= M;

        // Build the one that's closer and cheaper first
        double first_cost0 = cost0 + avg_d0 * 0.5;
        double first_cost1 = cost1 + avg_d1 * 0.5;
        if (first_cost0 <= first_cost1) {
            build_order[0] = 0; build_order[1] = 1;
        } else {
            build_order[0] = 1; build_order[1] = 0;
        }
    } else {
        num_plans = 1;
        active_plans[0] = corners[best_single];
        build_order[0] = 0;
    }
}

int current_phase = 0; // 0 = building first plan, 1 = building second plan, 2 = done

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();

    for (int p = 0; p < num_plans; p++) {
        plan_walls[p] = get_wall_cells(active_plans[p]);
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        // Determine current target plan
        int target_plan = build_order[current_phase];

        // Check if current target plan is complete
        if (current_phase < num_plans) {
            bool all_built = true;
            for (auto& wc : plan_walls[target_plan]) {
                if (!grid[wc.r][wc.c]) { all_built = false; break; }
            }
            if (all_built) {
                current_phase++;
                if (current_phase < num_plans) {
                    target_plan = build_order[current_phase];
                }
            }
        }

        if (current_phase >= num_plans) {
            // All plans built - all humans move to their nearest safe zone
            for (int i = 0; i < M; i++) {
                // Find closest safe zone
                int best_p = 0;
                int best_d = INF;
                for (int p = 0; p < num_plans; p++) {
                    auto& plan = active_plans[p];
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    int d = std::abs(humans[i].r - tr) + std::abs(humans[i].c - tc);
                    if (d < best_d) { best_d = d; best_p = p; }
                }

                auto& plan = active_plans[best_p];
                int tr = (plan.r_min + plan.r_max) / 2;
                int tc = (plan.c_min + plan.c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c) || !is_safe_side(plan, target.r, target.c)) {
                    bool found = false;
                    for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
                        for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }
                if (humans[i] != target) {
                    actions[i] = move_toward(humans[i], target);
                }
            }
        } else {
            // All humans work on the current target plan
            auto& my_walls = plan_walls[target_plan];
            auto& plan = active_plans[target_plan];
            int corner_r = plan.wall_row;
            int corner_c = plan.wall_col;

            for (int i = 0; i < M; i++) {
                int best_idx = -1;
                int best_priority = INF;

                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    int cdist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);
                    int priority = dist * 2 + cdist;
