                bool wall_done = true;
                for (int c = 1; c <= GRID_SIZE; c++) {
                    if (!grid[my_wall_row][c]) { wall_done = false; break; }
                }

                if (wall_done) {
                    // Move to safe zone
                    int safe_r;
                    if (human_wall_assignment_h[i] == 0) {
                        safe_r = std::max(1, dual_wall_top / 2);
                    } else {
                        safe_r = std::min(GRID_SIZE, dual_wall_bot + (GRID_SIZE - dual_wall_bot) / 2);
                    }
                    Point target = {safe_r, GRID_SIZE / 2};
                    if (!passable(target.r, target.c)) {
                        int s, e;
                        if (human_wall_assignment_h[i] == 0) { s = 1; e = dual_wall_top - 1; }
                        else { s = dual_wall_bot + 1; e = GRID_SIZE; }
                        for (int r = s; r <= e; r++) {
                            for (int c = 1; c <= GRID_SIZE; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_target; }
                            }
                        }
                        found_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    // Build wall
                    int target_col = -1;
                    int min_dist = INF;
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (grid[my_wall_row][c] || my_claimed[c]) continue;
                        int dist = std::abs(humans[i].r - my_wall_row) + std::abs(humans[i].c - c);
                        if (dist < min_dist) { min_dist = dist; target_col = c; }
                    }

