                        my_claimed[target_col] = true;
                        int stand_r = (human_wall_assignment_h[i] == 0) ? my_wall_row - 1 : my_wall_row + 1;
                        Point stand_pos = {stand_r, target_col};

                        if (!passable(stand_r, target_col)) {
                            int alts[4][2] = {{my_wall_row-1,target_col},{my_wall_row+1,target_col},
                                              {my_wall_row,target_col-1},{my_wall_row,target_col+1}};
                            bool found = false;
                            for (auto& a : alts) {
                                if (passable(a[0], a[1])) { stand_pos = {a[0], a[1]}; found = true; break; }
                            }
                            if (!found) { actions[i] = '.'; continue; }
                        }

                        if (humans[i] == stand_pos) {
                            if (can_build_wall(my_wall_row, target_col)) {
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == my_wall_row && humans[i].c + DC[d] == target_col) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back({my_wall_row, target_col});
                                        break;
                                    }
                                }
                            } else {
                                my_claimed[target_col] = false;
                                actions[i] = '.';
                            }
                        } else {
                            actions[i] = move_toward(humans[i], stand_pos);
                        }
                    }
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
