                best_tr = tr;
                best_br = br;
            }
        }
    }

    // Choose strategy
    // L-shape advantages: faster build, better pet isolation when corners are clean
    // Give L-shape a 20% bonus for faster construction
    double l_pair_effective = best_pair_score * 1.2;
    double l_single_effective = best_single_score * 1.3; // single is even faster

    if (l_pair_effective > best_dual_h && l_pair_effective > l_single_effective) {
        strategy_mode = 0;
        num_plans = 2;
        plans[0] = corners[best_pair[0]];
        plans[1] = corners[best_pair[1]];
    } else if (l_single_effective > best_dual_h) {
        strategy_mode = 0;
        num_plans = 1;
        plans[0] = corners[best_single];
    } else {
        strategy_mode = 1;
        dual_wall_top = best_tr;
        dual_wall_bot = best_br;
    }
}

// Human assignment for L-shape strategy
int human_plan_assignment[10]; // which plan (0 or 1)

// Wall cells to build for each plan
std::vector<Point> plan_walls[2];

void assign_humans_lshape() {
    if (num_plans == 1) {
        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
        return;
    }

    // Split humans between two plans based on proximity
    int count0 = M / 2;

    std::vector<std::pair<double, int>> preference(M);
    for (int i = 0; i < M; i++) {
        // Distance to center of plan 0 region
        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);

        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);

        preference[i] = {d0 - d1, i};
    }
    std::sort(preference.begin(), preference.end());

    int assigned0 = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned0 < count0) {
            human_plan_assignment[idx] = 0;
            assigned0++;
        } else {
            human_plan_assignment[idx] = 1;
        }
    }
}

// For dual horizontal wall fallback
int human_wall_assignment_h[10]; // 0=top, 1=bot

void assign_humans_dual_h() {
    int top_count = M / 2;
    std::vector<std::pair<int, int>> preference(M);
    for (int i = 0; i < M; i++) {
        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
    }
    std::sort(preference.begin(), preference.end());
    int assigned_top = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned_top < top_count) {
            human_wall_assignment_h[idx] = 0;
            assigned_top++;
        } else {
            human_wall_assignment_h[idx] = 1;
        }
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();

    if (strategy_mode == 0) {
        // L-shape mode
        for (int p = 0; p < num_plans; p++) {
            plan_walls[p] = get_wall_cells(plans[p]);
        }
        assign_humans_lshape();
    } else {
        // Dual horizontal wall mode
        assign_humans_dual_h();
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        if (strategy_mode == 0) {
            // L-shape strategy
            for (int i = 0; i < M; i++) {
                int my_plan = human_plan_assignment[i];
                auto& my_walls = plan_walls[my_plan];
                auto& plan = plans[my_plan];

                // Find best unbuilt wall cell: balance proximity to human and priority from corner outward
                int best_idx = -1;
                int best_priority = INF;

                // The intersection point of the L-shape
                int corner_r = plan.wall_row;
                int corner_c = plan.wall_col;

                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;

                    // Check not already claimed this turn
                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;

                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    // Distance from corner intersection (build from corner outward)
                    int corner_dist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);
                    // Combined priority: mostly distance but with a small bias toward corner
                    int priority = dist * 2 + corner_dist;
                    if (priority < best_priority) {
                        best_priority = priority;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
                    // All walls built - move to center of safe zone
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        // Find any passable cell in safe zone
                        bool found = false;
                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
                                if (passable(r, c)) {
                                    target = {r, c};
                                    found = true;
                                }
                            }
                        }
                    }
                    if (humans[i] != target) {
                        actions[i] = move_toward(humans[i], target);
                    }
                } else {
                    Point wall_target = my_walls[best_idx];

                    // Find a position adjacent to wall_target from the SAFE side
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;

                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;

                        // Prefer standing inside the safe zone
                        bool in_safe = is_safe_side(plan, sr, sc);

                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        // Give big bonus to safe-side positions
                        int effective_dist = in_safe ? dist : dist + 100;

                        if (effective_dist < best_stand_dist) {
                            best_stand_dist = effective_dist;
                            stand_pos = {sr, sc};
                        }
                    }

                    if (stand_pos.r == -1) {
                        // Can't find standing position, try any adjacent
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d];
                            int sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) {
                                stand_pos = {sr, sc};
                                break;
                            }
                        }
                    }

                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        // Build the wall
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wall_target);
                                    break;
                                }
                            }
                        } else {
                            // Pet blocking - try building a different adjacent wall cell
                            bool built_alt = false;
                            for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
                                if (w2 == best_idx) continue;
                                Point wc2 = my_walls[w2];
                                if (grid[wc2.r][wc2.c]) continue;
                                if (!can_build_wall(wc2.r, wc2.c)) continue;

                                bool adjacent = false;
                                int build_dir = -1;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true;
                                        build_dir = d;
                                        break;
                                    }
                                }
                                if (adjacent) {
                                    actions[i] = BUILD_CH[build_dir];
                                    walls_being_built.push_back(wc2);
                                    built_alt = true;
                                    break;
                                }
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        // Move toward standing position
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        } else {
            // Dual horizontal wall strategy (fallback)
            bool col_claimed_top[GRID_SIZE + 2], col_claimed_bot[GRID_SIZE + 2];
            memset(col_claimed_top, false, sizeof(col_claimed_top));
            memset(col_claimed_bot, false, sizeof(col_claimed_bot));

            for (int i = 0; i < M; i++) {
                int my_wall_row = (human_wall_assignment_h[i] == 0) ? dual_wall_top : dual_wall_bot;
                bool* my_claimed = (human_wall_assignment_h[i] == 0) ? col_claimed_top : col_claimed_bot;

                // Check if wall is complete
                bool wall_done = true;
                for (int c = 1; c <= GRID_SIZE; c++) {
                    if (!grid[my_wall_row][c]) { wall_done = false; break; }
                }

                if (wall_done) {
                    // Move to safe zone
                    int safe_r;
                    if (human_wall_assignment_h[i] == 0) {
                        safe_r = std::max(1, dual_wall_top / 2);
                    } else {
                        safe_r = std::min(GRID_SIZE, dual_wall_bot + (GRID_SIZE - dual_wall_bot) / 2);
                    }
                    Point target = {safe_r, GRID_SIZE / 2};
                    if (!passable(target.r, target.c)) {
                        int s, e;
                        if (human_wall_assignment_h[i] == 0) { s = 1; e = dual_wall_top - 1; }
                        else { s = dual_wall_bot + 1; e = GRID_SIZE; }
                        for (int r = s; r <= e; r++) {
                            for (int c = 1; c <= GRID_SIZE; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_target; }
                            }
                        }
                        found_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    // Build wall
                    int target_col = -1;
                    int min_dist = INF;
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (grid[my_wall_row][c] || my_claimed[c]) continue;
                        int dist = std::abs(humans[i].r - my_wall_row) + std::abs(humans[i].c - c);
                        if (dist < min_dist) { min_dist = dist; target_col = c; }
                    }

                    if (target_col == -1) {
                        actions[i] = '.';
                    } else {
                        my_claimed[target_col] = true;
                        int stand_r = (human_wall_assignment_h[i] == 0) ? my_wall_row - 1 : my_wall_row + 1;
                        Point stand_pos = {stand_r, target_col};

                        if (!passable(stand_r, target_col)) {
                            int alts[4][2] = {{my_wall_row-1,target_col},{my_wall_row+1,target_col},
                                              {my_wall_row,target_col-1},{my_wall_row,target_col+1}};
                            bool found = false;
                            for (auto& a : alts) {
                                if (passable(a[0], a[1])) { stand_pos = {a[0], a[1]}; found = true; break; }
                            }
                            if (!found) { actions[i] = '.'; continue; }
                        }

                        if (humans[i] == stand_pos) {
                            if (can_build_wall(my_wall_row, target_col)) {
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == my_wall_row && humans[i].c + DC[d] == target_col) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back({my_wall_row, target_col});
                                        break;
                                    }
                                }
                            } else {
                                my_claimed[target_col] = false;
                                actions[i] = '.';
                            }
                        } else {
                            actions[i] = move_toward(humans[i], stand_pos);
                        }
                    }
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
